# Auto-generated from static/index.html so the page is always bundled on Vercel.
# Regenerate after editing index.html:  python3 -c "open('page.py',"w").write(...)"
HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="utf-8"/>\n<meta name="viewport" content="width=device-width, initial-scale=1"/>\n<title>AI Studio</title>\n<style>\n  :root{\n    --bg:#0d0f14; --panel:#161a22; --panel2:#1d222c; --line:#283041;\n    --text:#e7ebf3; --muted:#8a93a6; --accent:#6d8bff; --accent2:#9a6dff;\n    --ok:#3ecf8e; --err:#ff6b6b; --radius:14px;\n  }\n  *{box-sizing:border-box}\n  body{margin:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;\n    background:var(--bg);color:var(--text);font-size:15px;min-height:100vh}\n  header{display:flex;align-items:center;justify-content:space-between;\n    padding:16px 24px;border-bottom:1px solid var(--line)}\n  header h1{font-size:17px;margin:0;font-weight:600}\n  header h1 span{background:linear-gradient(90deg,var(--accent),var(--accent2));\n    -webkit-background-clip:text;background-clip:text;color:transparent}\n  .btn{background:var(--panel2);color:var(--text);border:1px solid var(--line);\n    padding:9px 15px;border-radius:9px;cursor:pointer;font-size:13px}\n  .btn:hover{border-color:var(--accent)}\n  .btn.primary{background:linear-gradient(90deg,var(--accent),var(--accent2));border:0;font-weight:600;font-size:15px}\n  .btn.primary:disabled{opacity:.45;cursor:not-allowed}\n  .wrap{max-width:880px;margin:0 auto;padding:26px 22px}\n  .modeToggle{display:flex;gap:8px;justify-content:center;margin-bottom:24px}\n  .modeToggle .tab{padding:10px 22px;border-radius:999px;background:var(--panel);\n    border:1px solid var(--line);cursor:pointer;color:var(--muted);font-weight:500}\n  .modeToggle .tab.active{color:var(--text);border-color:var(--accent);background:var(--panel2)}\n  .drop{border:2px dashed var(--line);border-radius:var(--radius);padding:40px 22px;text-align:center;\n    color:var(--muted);cursor:pointer;background:var(--panel);transition:.15s}\n  .drop:hover{border-color:var(--accent);color:var(--text)}\n  .drop.has{padding:14px}\n  .drop img{max-width:100%;max-height:300px;border-radius:10px}\n  .drop .big{font-size:16px;margin-bottom:6px}\n  textarea{width:100%;background:var(--panel2);border:1px solid var(--line);color:var(--text);\n    border-radius:10px;padding:14px;font-size:15px;font-family:inherit;resize:vertical;min-height:80px;margin-top:16px}\n  .result{margin-top:26px;min-height:120px;display:none;flex-wrap:wrap;gap:14px;\n    background:var(--panel);border:1px solid var(--line);border-radius:var(--radius);padding:16px;\n    align-items:center;justify-content:center}\n  .result.show{display:flex}\n  .result img,.result video{max-width:100%;max-height:420px;border-radius:10px}\n  .out{position:relative}\n  .out a.dl{position:absolute;top:8px;right:8px;background:rgba(0,0,0,.6);padding:6px 10px;\n    border-radius:8px;color:#fff;text-decoration:none;font-size:12px}\n  .spinner{width:38px;height:38px;border:3px solid var(--line);border-top-color:var(--accent);\n    border-radius:50%;animation:spin 1s linear infinite}\n  @keyframes spin{to{transform:rotate(360deg)}}\n  .stat{text-align:center;color:var(--muted);font-size:13px;margin-top:10px;min-height:18px}\n  .msg{padding:11px 14px;border-radius:9px;font-size:13px;margin-top:14px;display:none}\n  .msg.err{background:rgba(255,107,107,.12);color:var(--err);border:1px solid rgba(255,107,107,.3);display:block}\n  .badge{font-size:10px;padding:2px 7px;border-radius:999px;background:var(--panel2);\n    color:var(--muted);border:1px solid var(--line);margin-left:6px}\n  .badge.set{color:var(--ok);border-color:rgba(62,207,142,.4)}\n  .modal{position:fixed;inset:0;background:rgba(0,0,0,.65);display:none;align-items:center;justify-content:center;z-index:50}\n  .modal.show{display:flex}\n  .modal .card{background:var(--panel);border:1px solid var(--line);border-radius:var(--radius);\n    padding:22px;max-width:460px;width:92%}\n  label{display:block;font-size:12px;color:var(--muted);margin:16px 0 6px}\n  input[type=text],input[type=password]{width:100%;background:var(--panel2);border:1px solid var(--line);\n    color:var(--text);border-radius:8px;padding:11px;font-size:14px}\n  .hint{font-size:11px;color:var(--muted);margin-top:5px}\n</style>\n</head>\n<body>\n<header>\n  <h1><span>◆ AI Studio</span></h1>\n  <button class="btn" onclick="openSettings()">⚙ Settings <span id="cfgBadge" class="badge"></span></button>\n</header>\n\n<div class="wrap">\n  <div class="modeToggle">\n    <div class="tab active" id="tab-edit" onclick="setMode(\'edit\')">✏️ Edit</div>\n    <div class="tab" id="tab-generate" onclick="setMode(\'generate\')">🖼️ Generate</div>\n    <div class="tab" id="tab-video" onclick="setMode(\'video\')">🎬 Image→Video</div>\n  </div>\n\n  <!-- 1. drop image (hidden in Generate mode) -->\n  <div id="imageBlock">\n    <div class="drop" id="drop" onclick="document.getElementById(\'file\').click()">\n      <div class="big">⬆ Drop an image here</div>\n      <div>or click to choose a file</div>\n      <input type="file" id="file" accept="image/*" hidden/>\n    </div>\n  </div>\n\n  <!-- 2. prompt -->\n  <textarea id="prompt" placeholder="Describe what you want… e.g. \'make it cyberpunk neon at night\'"></textarea>\n\n  <!-- resolution + count -->\n  <div style="display:flex;gap:12px;margin-top:14px;align-items:flex-end">\n    <div style="flex:1">\n      <label style="display:block;color:var(--muted);font-size:12px;margin-bottom:6px">Resolution</label>\n      <select id="resolution" style="width:100%;background:var(--panel2);border:1px solid var(--line);color:var(--text);border-radius:8px;padding:10px"></select>\n    </div>\n    <div id="countWrap" style="flex:1">\n      <label style="display:block;color:var(--muted);font-size:12px;margin-bottom:6px">Images</label>\n      <select id="count" style="width:100%;background:var(--panel2);border:1px solid var(--line);color:var(--text);border-radius:8px;padding:10px">\n        <option>1</option><option>2</option><option>3</option><option>4</option>\n      </select>\n    </div>\n  </div>\n\n  <!-- 3. generate -->\n  <button class="btn primary" id="goBtn" style="width:100%;margin-top:16px;padding:14px" onclick="run()">\n    Generate\n  </button>\n  <div class="stat" id="stat"></div>\n  <div class="msg" id="msg"></div>\n\n  <!-- 4. result -->\n  <div class="result" id="result"></div>\n</div>\n\n<!-- Settings -->\n<div class="modal" id="settings">\n  <div class="card">\n    <div style="display:flex;justify-content:space-between;align-items:center">\n      <h3 style="margin:0">Settings</h3>\n      <button class="btn" onclick="closeSettings()">✕</button>\n    </div>\n    <p class="hint">Saved only in this browser. Sent to your local server per request, never written to disk.</p>\n\n    <label>xAI API key</label>\n    <input type="password" id="cfg_key" placeholder="xai-..." onfocus="if(this.value.includes(\'•\'))this.value=\'\'"/>\n    <div class="hint">console.x.ai → API Keys. All three tabs use this one key.</div>\n\n    <button class="btn primary" style="width:100%;margin-top:18px;padding:11px" onclick="saveCfg()">Save</button>\n  </div>\n</div>\n\n<script>\nlet mode = "edit";               // edit | generate | video\nlet curImage = null;             // data URL\nlet curW = 0, curH = 0;          // source image dimensions\nconst TASK_OF = { edit:"edit", generate:"generate", video:"i2v" };\nconst RES_OPTS = {\n  edit:     [["1k","1K"],["2k","2K"]],\n  generate: [["1k","1K"],["2k","2K"]],\n  video:    [["480p","480p"],["720p","720p"]],\n};\n\nfunction cfg(){ try{return JSON.parse(localStorage.getItem("ai_cfg")||"{}")}catch(e){return {}} }\nfunction setCfg(c){ localStorage.setItem("ai_cfg", JSON.stringify(c)); }\n\nfunction setMode(m){\n  mode = m;\n  document.getElementById("tab-edit").classList.toggle("active", m==="edit");\n  document.getElementById("tab-generate").classList.toggle("active", m==="generate");\n  document.getElementById("tab-video").classList.toggle("active", m==="video");\n  document.getElementById("goBtn").textContent =\n    m==="video" ? "Generate Video" : m==="edit" ? "Edit Image" : "Generate Image";\n  document.getElementById("prompt").placeholder =\n    m==="video" ? "Describe the motion… e.g. \'slow cinematic zoom, rain falling\'"\n    : m==="edit" ? "Tell it what to change… e.g. \'change her outfit to a beautiful red saree\'"\n    : "Describe the image… e.g. \'a neon-lit Tokyo street in the rain, cinematic\'";\n  // Generate is text-to-image: no source image needed\n  document.getElementById("imageBlock").style.display = m==="generate" ? "none" : "block";\n  // Image count only applies to image generation/editing, not video\n  document.getElementById("countWrap").style.display = m==="video" ? "none" : "block";\n  // populate resolution choices for this mode\n  const sel=document.getElementById("resolution"); sel.innerHTML="";\n  RES_OPTS[m].forEach(([val,label],i)=>{\n    const o=document.createElement("option"); o.value=val; o.textContent=label;\n    if(i===0) o.selected=true; sel.appendChild(o);\n  });\n}\n\n/* ---- image drop / pick ---- */\nfunction init(){\n  const file=document.getElementById("file");\n  file.addEventListener("change",e=>{loadFile(e.target.files[0]);file.value="";});\n  const drop=document.getElementById("drop");\n  drop.addEventListener("dragover",e=>{e.preventDefault();drop.style.borderColor="var(--accent)";});\n  drop.addEventListener("dragleave",()=>drop.style.borderColor="");\n  drop.addEventListener("drop",e=>{e.preventDefault();drop.style.borderColor="";loadFile(e.dataTransfer.files[0]);});\n  setMode("edit");   // populates the resolution dropdown\n  updateBadge();\n}\nfunction loadFile(f){\n  if(!f || !f.type.startsWith("image/")) return;\n  const r=new FileReader();\n  r.onload=e=>{ downscale(e.target.result, 1024, (dataUrl,w,h)=>{ curImage=dataUrl; curW=w; curH=h; showPreview(); }); };\n  r.readAsDataURL(f);\n}\n// Resize big photos down to maxSide before sending — keeps payloads small\n// so the browser never has to ship/handle multi-MB base64. Reports final dims.\nfunction downscale(dataUrl, maxSide, cb){\n  const img=new Image();\n  img.onload=()=>{\n    let w=img.width, h=img.height;\n    if(Math.max(w,h)<=maxSide){ cb(dataUrl, w, h); return; }\n    const s=maxSide/Math.max(w,h); w=Math.round(w*s); h=Math.round(h*s);\n    const c=document.createElement("canvas"); c.width=w; c.height=h;\n    c.getContext("2d").drawImage(img,0,0,w,h);\n    cb(c.toDataURL("image/jpeg",0.9), w, h);\n  };\n  img.onerror=()=>cb(dataUrl, 0, 0);\n  img.src=dataUrl;\n}\nfunction showPreview(){\n  const d=document.getElementById("drop");\n  d.classList.add("has");\n  d.innerHTML=`<img src="${curImage}"/><div class="hint" style="margin-top:8px">Click to change image</div>\n               <input type="file" id="file" accept="image/*" hidden/>`;\n  document.getElementById("file").addEventListener("change",e=>{loadFile(e.target.files[0]);});\n}\n\n/* ---- generate ---- */\nasync function run(){\n  const c=cfg();\n  const prompt=document.getElementById("prompt").value.trim();\n  const stat=document.getElementById("stat");\n  const res=document.getElementById("result");\n  msg("");\n\n  // key may be blank — the server falls back to its XAI_API_KEY env var\n  if(mode!=="generate" && !curImage) return err("Drop or choose a source image first.");\n  if(!prompt)   return err("Type a prompt describing what you want.");\n\n  const btn=document.getElementById("goBtn"); btn.disabled=true;\n  res.className="result show"; res.innerHTML=\'<div class="spinner"></div>\';\n  stat.textContent = mode==="video"\n    ? "Generating with Grok Imagine… video can take a minute or two."\n    : "Generating with Grok Imagine…";\n\n  const task = TASK_OF[mode];\n  const opts = buildOpts();\n  try{\n    if(mode==="video"){ await runVideo(c.key, prompt, opts, stat, res); return; }\n    const r=await fetch("/go/run",{method:"POST",headers:{"Content-Type":"application/json"},\n      body:JSON.stringify({task,provider:"xai",model:"grok-imagine",api_key:c.key,prompt,\n        image:curImage,images:[curImage],opts})});\n    const data=await r.json();\n    if(!r.ok || data.error) throw new Error(data.error||("HTTP "+r.status));\n\n    stat.textContent="";\n    const urls = data.urls && data.urls.length ? data.urls : [data.url];\n    res.innerHTML="";\n    urls.forEach((u,i)=>{\n      const src = (u.startsWith("data:") || u.startsWith("/")) ? u : "/go/proxy?url="+encodeURIComponent(u);\n      const box=document.createElement("div"); box.className="out";\n      box.innerHTML = data.type==="video"\n        ? `<video src="${src}" controls autoplay loop></video><a class="dl" href="${src}" download="output.mp4">⬇</a>`\n        : `<img src="${src}"/><a class="dl" href="${src}" download="output_${i+1}.png">⬇</a>`;\n      res.appendChild(box);\n    });\n  }catch(e){ err(e.message); stat.textContent=""; res.className="result"; }\n  finally{ btn.disabled=false; }\n}\n\n// Video: start the job, then poll status from the browser (works within\n// serverless function timeouts on Vercel).\nasync function runVideo(apiKey, prompt, opts, stat, res){\n  const post=(url,body)=>fetch(url,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)}).then(r=>r.json());\n  stat.textContent="Starting video…";\n  const s=await post("/go/video/start",{api_key:apiKey,prompt,image:curImage,opts});\n  if(s.error) throw new Error(s.error);\n  let url=s.url;\n  if(!url){\n    const rid=s.request_id;\n    for(let i=0;i<90;i++){            // ~6 min at 4s intervals\n      await new Promise(r=>setTimeout(r,4000));\n      const st=await post("/go/video/status",{api_key:apiKey,request_id:rid});\n      if(st.error) throw new Error(st.error);\n      if(st.status==="done"){ url=st.url; break; }\n      stat.textContent="Rendering video… "+((i+1)*4)+"s";\n    }\n  }\n  if(!url) throw new Error("Video timed out — try again.");\n  stat.textContent="";\n  const src=(url.startsWith("data:")||url.startsWith("/"))?url:"/go/proxy?url="+encodeURIComponent(url);\n  res.innerHTML=`<div class="out"><video src="${src}" controls autoplay loop></video>`+\n                `<a class="dl" href="${src}" download="output.mp4">⬇</a></div>`;\n}\n\n// Build opts: resolution (per tab), image count, and aspect for generate/video.\nfunction buildOpts(){\n  const o={ resolution: document.getElementById("resolution").value };\n  if(mode==="generate" || mode==="video"){\n    o.aspect_ratio = (curW && curH && curW>curH) ? "16:9" : "9:16";\n  }\n  if(mode==="edit" || mode==="generate"){\n    o.n = parseInt(document.getElementById("count").value) || 1;\n  }\n  return o;\n}\n\nfunction msg(t){const m=document.getElementById("msg");if(!t){m.className="msg";m.textContent="";}else{m.className="msg err";m.textContent=t;}}\nfunction err(t){ msg(t); return false; }\n\n/* ---- settings ---- */\nfunction openSettings(){\n  const c=cfg();\n  document.getElementById("cfg_key").value = c.key ? c.key.replace(/./g,\'•\') : "";\n  document.getElementById("settings").classList.add("show");\n}\nfunction closeSettings(){document.getElementById("settings").classList.remove("show");}\nfunction saveCfg(){\n  const c=cfg();\n  const kv=document.getElementById("cfg_key").value.trim();\n  if(kv && !kv.includes(\'•\')) c.key=kv;\n  setCfg(c); updateBadge(); closeSettings();\n}\nfunction updateBadge(){\n  const c=cfg();\n  const b=document.getElementById("cfgBadge");\n  const ok = !!c.key;\n  b.textContent = ok ? "ready" : "setup"; b.className="badge"+(ok?" set":"");\n}\n\ninit();\n</script>\n</body>\n</html>\n'
